"use strict";parserFactory.register("rtd.moe",()=>new FakeParser);class FakeParser extends Parser{constructor(){super()}async getChapterUrls(){let e=[];for(let t=1;t<30;++t)e.push({sourceUrl:`https://rtd.moe/Chapter/${t}.html`,title:`Chapter ${t}`,newArc:null});return e}findContent(e){return Parser.findConstrutedContent(e)}extractTitleImpl(e){return e.querySelector("h1")}async fetchChapter(e){let t=Parser.makeEmptyDocForContent(e);return this.addTitleToChapter(t,e),await new Promise(e=>setTimeout(e,1e3)),t.dom}addTitleToChapter(e,t){let r=e.dom.createElement("h1");r.textContent=t,e.content.appendChild(r)}getInformationEpubItemChildNodes(){return[]}}